public class Person {
  private String name;
  private int age;

  public String getName() {
    return name;
  }

  public void setName(String name) {
    this.name = name;
  }

  public int getAge() {
    return age;
  }

  public void setAge(int age) {
    if (age >= 0) {
      this.age = age;
    } else {
      System.out.println("Yaş mənfi ola bilməz!");
    }
  }

  public static void main(String[] args) {
    Person person = new Person();
    person.setName("Ali");
    person.setAge(25);
    System.out.println("Ad: " + person.getName() + ", Yaş: " + person.getAge());
    person.setAge(-5);
  }
}
// Çıxış:
// Ad: Ali, Yaş: 25
// Yaş mənfi ola bilməz!

public class BankAccount {
  private String accountNumber;
  private double balance;

  public BankAccount(String accountNumber, double balance) {
    this.accountNumber = accountNumber;
    this.balance = balance;
  }

  public String getAccountNumber() {
    return accountNumber;
  }

  public double getBalance() {
    return balance;
  }

  public void deposit(double amount) {
    if (amount > 0) {
      balance += amount;
      System.out.println(amount + " AZN yatırıldı. Yeni balans: " + balance);
    } else {
      System.out.println("Məbləğ müsbət olmalıdır!");
    }
  }

  public void withdraw(double amount) {
    if (amount > 0 && amount <= balance) {
      balance -= amount;
      System.out.println(amount + " AZN çıxarıldı. Yeni balans: " + balance);
    } else {
      System.out.println("Kifayət qədər balans yoxdur və ya məbləğ yanlışdır!");
    }
  }

  public static void main(String[] args) {
    BankAccount account = new BankAccount("AZ123456", 1000.0);
    account.deposit(500.0);
    account.withdraw(200.0);
    account.withdraw(2000.0);
    System.out.println("Hesab nömrəsi: " + account.getAccountNumber() + ", Balans: " + account.getBalance());
  }
}
// Çıxış:
// 500.0 AZN yatırıldı. Yeni balans: 1500.0
// 200.0 AZN çıxarıldı. Yeni balans: 1300.0
// Kifayət qədər balans yoxdur və ya məbləğ yanlışdır!
// Hesab nömrəsi: AZ123456, Balans: 1300.0

