public class BankAccount {
  private String accountNumber;
  private double balance;

  public BankAccount(String accountNumber, double balance) {
    this.accountNumber = accountNumber;
    this.balance = balance;
  }

  public String getAccountNumber() {
    return accountNumber;
  }

  public double getBalance() {
    return balance;
  }

  public void deposit(double amount) {
    if (amount > 0) {
      balance += amount;
      System.out.println(amount + " USD deposited. New balance: " + balance);
    } else {
      System.out.println("Amount must be positive!");
    }
  }

  public void withdraw(double amount) {
    if (amount > 0 && amount <= balance) {
      balance -= amount;
      System.out.println(amount + " USD withdrawn. New balance: " + balance);
    } else {
      System.out.println("Insufficient balance or invalid amount!");
    }
  }

  public static void main(String[] args) {
    BankAccount account = new BankAccount("US123456", 1000.0);
    account.deposit(500.0);
    account.withdraw(200.0);
    account.withdraw(2000.0);
    System.out.println("Account Number: " + account.getAccountNumber() + ", Balance: " + account.getBalance());
  }
}
// Output:
// 500.0 USD deposited. New balance: 1500.0
// 200.0 USD withdrawn. New balance: 1300.0
// Insufficient balance or invalid amount!
// Account Number: US123456, Balance: 1300.0

